import { useState, useEffect } from "react";

function StudyWithFriendsPage({ onBack, onLogout }) {
  const [seconds, setSeconds] = useState(0);

  useEffect(() => {
    const interval = setInterval(() => {
      setSeconds((s) => s + 1);
    }, 1000);

    return () => clearInterval(interval);
  }, []);

  return (
    <div className="container-center">
      <div className="card">
        <div className="topbar">
          <div>
            <div className="subtitle">Canlı çalışma odası</div>
            <h2 className="title" style={{ marginBottom: 0 }}>
              Live Study Room
            </h2>
          </div>
          <button className="btn btn-danger" onClick={onLogout}>
            Çıkış Yap
          </button>
        </div>

        <div className="section-title">Oturum sayacı</div>
        <div className="pre" style={{ textAlign: "center", fontSize: 22 }}>
          {seconds} saniye
        </div>

        <div className="actions">
          <button className="btn btn-secondary" onClick={onBack}>
            Geri
          </button>
        </div>
      </div>
    </div>
  );
}

export default StudyWithFriendsPage;
